import { 菩薩坐身, 上臂常勢, 前臂 } from './pusa.js';
import { 五鈷鈴 } from '../bujian/chiwu.js';
import { 側拳, 臂釧, 腕釧 } from '../bujian/index.js';
export const 金剛語 = (bi) => 菩薩坐身(bi, {
    臂(bi, 筆) {
        const { M, Qk, S, 骨, 衣, 細, 陰, 陽 } = 筆;
        骨(() => { 上臂常勢(筆, -1, 40.0); 上臂常勢(筆, 1, 40.2); });
        // 尊右：前臂橫入，仰掌承鈴當胸
        骨(() => 陽(() => 前臂(bi, 筆, [-13.7, 40.1], [-7.5, 41.3], { 寬根: 2.5, 寬梢: 1.9, 弓: 0.4, 肘帽: true })));
        衣(() => {
            M(-10.8, 41.0);
            Qk(-8.7, 42.0, -6.6, 41.3);
            S();
            M(-10.5, 41.7);
            Qk(-8.7, 42.5, -7.0, 41.9);
            S();
            細(() => {
                for (const t of [0, 1, 2]) {
                    M(-10.3 + t * 1.15, 40.75 - t * 0.1);
                    Qk(-10.0 + t * 1.15, 40.4 - t * 0.1, -9.6 + t * 1.15, 40.25 - t * 0.1);
                    S();
                }
            });
        });
        五鈷鈴(bi, -8.8, 39.0, 0.85, true);
        // 尊左：前臂垂，拳安腰際
        骨(() => 陰(() => 前臂(bi, 筆, [13.8, 40.3], [13.0, 45.6], { 寬根: 2.4, 寬梢: 1.8, 弓: -0.3, 肘帽: false })));
        側拳(bi, 12.8, 47.9, Math.PI / 2, 1.05, -1);
        // 嚴
        臂釧(bi, -1, 12.1, 14.5, 33.4);
        臂釧(bi, 1, 12.1, 14.5, 33.4);
        細(() => {
            腕釧(bi, [[-11.8, 40.0, -11.0, 40.9, -10.2, 41.7], [-11.3, 39.4, -10.5, 40.3, -9.7, 41.1]], [-10.8, 40.4]);
            腕釧(bi, [[11.9, 44.9, 13.0, 45.4, 14.1, 45.0], [11.8, 45.8, 12.9, 46.3, 14.0, 45.9]], [12.9, 45.8]);
        });
    },
});
